#include <stdio.h>
#include <string.h>
#include <math.h>
#include <stdlib.h>
#include <cuda_runtime.h>

#define OPEN

FILE *fp;

struct Node
{
	int starting;
	int no_of_edges;
};

void BFSGraph(int argc, char** argv);

void Usage(int argc, char**argv){
	fprintf(stderr,"Usage: %s <num_threads> <input_file>\n", argv[0]);
}

__global__ void bfs_step1(int no_of_nodes, bool* h_graph_mask, Node* h_graph_nodes, int* h_graph_edges, bool* h_graph_visited, int* h_cost, bool* h_updating_graph_mask) {
	int tid = blockIdx.x * blockDim.x + threadIdx.x;
	if (tid < no_of_nodes) {
		if (h_graph_mask[tid] == true) { 
			h_graph_mask[tid] = false;
			int start = h_graph_nodes[tid].starting;
			int end = start + h_graph_nodes[tid].no_of_edges;
			for (int i = start; i < end; i++) {
				int id = h_graph_edges[i];
				if (!h_graph_visited[id]) {
					h_cost[id] = h_cost[tid] + 1;
					h_updating_graph_mask[id] = true;
				}
			}
		}
	}
}

__global__ void bfs_step2(int no_of_nodes, bool* h_updating_graph_mask, bool* h_graph_mask, bool* h_graph_visited, bool* d_stop) {
	int tid = blockIdx.x * blockDim.x + threadIdx.x;
	if (tid < no_of_nodes) {
		if (h_updating_graph_mask[tid] == true) {
			h_graph_mask[tid] = true;
			h_graph_visited[tid] = true;
			*d_stop = true;
			h_updating_graph_mask[tid] = false;
		}
	}
}

int main(int argc, char** argv) 
{
	BFSGraph(argc, argv);
	return 0;
}

void BFSGraph(int argc, char** argv) 
{
	int no_of_nodes = 0;
	int edge_list_size = 0;
	char *input_f;
	int num_omp_threads;

	if(argc != 3){
		Usage(argc, argv);
		exit(0);
	}

	num_omp_threads = atoi(argv[1]);
	input_f = argv[2];

	printf("Reading File\n");

	fp = fopen(input_f,"r");
	if(!fp)
	{
		printf("Error Reading graph file\n");
		return;
	}

	int source = 0;

	fscanf(fp,"%d",&no_of_nodes);

	Node* h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
	bool *h_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
	bool *h_updating_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
	bool *h_graph_visited = (bool*) malloc(sizeof(bool)*no_of_nodes);

	int start, edgeno;   

	for(unsigned int i = 0; i < no_of_nodes; i++) 
	{
		fscanf(fp,"%d %d",&start,&edgeno);
		h_graph_nodes[i].starting = start;
		h_graph_nodes[i].no_of_edges = edgeno;
		h_graph_mask[i]=false;
		h_updating_graph_mask[i]=false;
		h_graph_visited[i]=false;
	}

	fscanf(fp,"%d",&source);

	h_graph_mask[source]=true;
	h_graph_visited[source]=true;

	fscanf(fp,"%d",&edge_list_size);

	int id,cost;
	int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
	for(int i=0; i < edge_list_size ; i++)
	{
		fscanf(fp,"%d",&id);
		fscanf(fp,"%d",&cost);
		h_graph_edges[i] = id;
	}

	if(fp)
		fclose(fp);    

	int* h_cost = (int*) malloc(sizeof(int)*no_of_nodes);
	for(int i=0;i<no_of_nodes;i++)
		h_cost[i]=-1;
	h_cost[source]=0;

	printf("Start traversing the tree\n");

	int k=0;
#ifdef OPEN
	double start_time = 0.0;
	cudaEvent_t start_event, stop_event;
	cudaEventCreate(&start_event);
	cudaEventCreate(&stop_event);
	cudaEventRecord(start_event);
#endif

	bool stop;

	// Device pointers
	Node* d_graph_nodes;
	bool* d_graph_mask;
	bool* d_updating_graph_mask;
	bool* d_graph_visited;
	int* d_graph_edges;
	int* d_cost;
	bool* d_stop_flag;

	cudaMalloc(&d_graph_nodes, sizeof(Node)*no_of_nodes);
	cudaMalloc(&d_graph_mask, sizeof(bool)*no_of_nodes);
	cudaMalloc(&d_updating_graph_mask, sizeof(bool)*no_of_nodes);
	cudaMalloc(&d_graph_visited, sizeof(bool)*no_of_nodes);
	cudaMalloc(&d_graph_edges, sizeof(int)*edge_list_size);
	cudaMalloc(&d_cost, sizeof(int)*no_of_nodes);
	cudaMalloc(&d_stop_flag, sizeof(bool));

	cudaMemcpy(d_graph_nodes, h_graph_nodes, sizeof(Node)*no_of_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_graph_mask, h_graph_mask, sizeof(bool)*no_of_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, sizeof(bool)*no_of_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_graph_visited, h_graph_visited, sizeof(bool)*no_of_nodes, cudaMemcpyHostToDevice);
	cudaMemcpy(d_graph_edges, h_graph_edges, sizeof(int)*edge_list_size, cudaMemcpyHostToDevice);
	cudaMemcpy(d_cost, h_cost, sizeof(int)*no_of_nodes, cudaMemcpyHostToDevice);

	int threads_per_block = 256;
	int blocks = (no_of_nodes + threads_per_block - 1) / threads_per_block;

	do {
		stop = false;
		cudaMemcpy(d_stop_flag, &stop, sizeof(bool), cudaMemcpyHostToDevice);

#ifdef OPEN
#endif
		bfs_step1<<<blocks, threads_per_block>>>(no_of_nodes, d_graph_mask, d_graph_nodes, d_graph_edges, d_graph_visited, d_cost, d_updating_graph_mask);

#ifdef OPEN
#endif
		bfs_step2<<<blocks, threads_per_block>>>(no_of_nodes, d_updating_graph_mask, d_graph_mask, d_graph_visited, d_stop_flag);

		cudaMemcpy(&stop, d_stop_flag, sizeof(bool), cudaMemcpyDeviceToHost);
		k++;
	} while(stop);

#ifdef OPEN
	cudaEventRecord(stop_event);
	cudaEventSynchronize(stop_event);
	float elapsed_time = 0.0;
	cudaEventElapsedTime(&elapsed_time, start_event, stop_event);
	printf("Compute time: %lf\n", elapsed_time / 1000.0);
	cudaEventDestroy(start_event);
	cudaEventDestroy(stop_event);
#endif

	FILE *fpo = fopen("result.txt","w");
	for(int i=0;i<no_of_nodes;i++)
		fprintf(fpo,"%d) cost:%d\n",i,h_cost[i]);
	fclose(fpo);
	printf("Result stored in result.txt\n");

	free(h_graph_nodes);
	free(h_graph_edges);
	free(h_graph_mask);
	free(h_updating_graph_mask);
	free(h_graph_visited);
	free(h_cost);

	cudaFree(d_graph_nodes);
	cudaFree(d_graph_edges);
	cudaFree(d_graph_mask);
	cudaFree(d_updating_graph_mask);
	cudaFree(d_graph_visited);
	cudaFree(d_cost);
	cudaFree(d_stop_flag);
}

